import React, { useContext, useEffect, useState } from "react";
import NewPostForm from "../Components/Forms/NewPostForm";
import { submitNewPost } from "../lib/api";
import AuthContext from "../store/auth-context";
import Banner from "../Components/Banner";
import { useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";

const NewPostPage = () => {
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [newPostId, setNewPostId] = useState(null);
  const authContext = useContext(AuthContext);
  const navigate = useNavigate();
  const { t } = useTranslation();

  const onSubmit = (newPost, formikHelpers) => {
    submitNewPost(newPost, authContext.token)
      .then(post => { setTimeout(() => { setNewPostId(post.id); setIsSubmitted(true); }, 2000); })
      .catch(console.log)
      .finally(() => { setTimeout(() => formikHelpers.setSubmitting(false), 2000); });
  };

  useEffect(() => {
    setTimeout(() => { if (isSubmitted) { setIsSubmitted(false); navigate(`/post/${newPostId}`); } }, 2000);
  }, [isSubmitted]);

  return (
    <div className="ink-page page-fade-in">
      <div className="ink-form-wrap">
        <NewPostForm isSubmitted={isSubmitted} onSubmit={onSubmit} />
        {isSubmitted && <Banner className="text-success border-success mt-4" message={`${t("addedBy", { type: "post" })} ${authContext.userName}`} />}
      </div>
    </div>
  );
};
export default NewPostPage;
